/* MODERN CSS - RECURRING BILLS DASHBOARD */

:root {
    --bg-color: rgb(248, 244, 240);
    --sidebar-bg: rgb(32, 31, 36);
    --white: rgb(255, 255, 255);
    --text-main: rgb(32, 31, 36);
    --text-muted: rgb(105, 104, 104);
    --text-light: rgb(179, 179, 179);
    --primary-teal: rgb(39, 124, 120);
    --danger-red: rgb(201, 71, 54);
    --border-color: rgb(242, 242, 242);
    --input-border: rgb(152, 144, 139);
    --content-bg: rgb(242, 243, 247);
    --font-main: 'Inter', sans-serif;
}

* {
    box-sizing: border-box;
    word-break: break-word;
}

body {
    margin: 0;
    padding: 0;
    font-family: var(--font-main);
    background-color: var(--bg-color);
    color: var(--text-main);
}

/* LAYOUT */
.dashboard {
    display: flex;
    min-height: 1024px;
    max-width: 1440px;
    margin: 0 auto;
}

/* SIDEBAR */
.sidebar {
    width: 300px;
    background-color: var(--sidebar-bg);
    display: flex;
    flex-direction: column;
    flex-shrink: 0;
    padding-bottom: 24px;
}

.sidebar__logo-container {
    height: 102px;
    display: flex;
    align-items: center;
    padding-left: 32px;
}

.sidebar__logo {
    min-width: 121px;
    min-height: 22px;
    background-color: var(--white);
    border-radius: 4px;
}

.sidebar__nav {
    flex-grow: 1;
    display: flex;
    flex-direction: column;
    gap: 4px;
    padding-right: 24px;
}

.sidebar__item {
    display: flex;
    align-items: center;
    gap: 16px;
    padding: 16px 32px;
    text-decoration: none;
    color: var(--text-light);
    font-weight: 700;
    font-size: 16px;
    transition: all 0.3s ease;
    border-left: 4px solid transparent;
}

.sidebar__item:hover {
    color: var(--white);
}

.sidebar__item--active {
    background-color: var(--bg-color);
    color: var(--text-main);
    border-radius: 0 12px 12px 0;
    border-left: 4px solid var(--primary-teal);
}

.sidebar__item i {
    min-width: 24px;
    text-align: center;
    font-size: 20px;
}

.sidebar__footer {
    margin-top: auto;
}

/* MAIN CONTENT */
.main-content {
    flex-grow: 1;
    padding: 32px 40px;
    background-color: var(--content-bg);
    display: flex;
    flex-direction: column;
    gap: 32px;
}

.main-content__header h1 {
    font-size: 32px;
    font-weight: 700;
    color: var(--text-main);
    margin: 0;
}

.content-grid {
    display: flex;
    gap: 24px;
    align-items: flex-start;
}

/* LEFT COLUMN */
.content-left {
    width: 337px;
    display: flex;
    flex-direction: column;
    gap: 24px;
    flex-shrink: 0;
}

.total-bills-card {
    background-color: var(--sidebar-bg);
    border-radius: 12px;
    padding: 24px;
    color: var(--white);
    display: flex;
    flex-direction: column;
    gap: 32px;
}

.total-bills-card__icon {
    font-size: 40px;
    min-height: 40px;
    min-width: 40px;
}

.total-bills-card__label {
    font-size: 14px;
    font-weight: 400;
    margin-bottom: 11px;
}

.total-bills-card__amount {
    font-size: 32px;
    font-weight: 700;
}

.summary-card {
    background-color: var(--white);
    border-radius: 12px;
    padding: 20px;
    display: flex;
    flex-direction: column;
    gap: 20px;
}

.summary-card__title {
    font-size: 16px;
    font-weight: 700;
    margin: 0;
}

.summary-card__list {
    display: flex;
    flex-direction: column;
    gap: 16px;
}

.summary-card__item {
    display: flex;
    justify-content: space-between;
    align-items: center;
    font-size: 12px;
}

.summary-card__label {
    color: var(--text-muted);
}

.summary-card__value {
    font-weight: 700;
    color: var(--text-main);
}

.summary-card__value--danger {
    color: var(--danger-red);
}

.summary-card__divider {
    min-height: 1px;
    width: 100%;
    background-color: var(--border-color);
}

/* RIGHT COLUMN - TABLE */
.content-right {
    flex-grow: 1;
    background-color: var(--white);
    border-radius: 12px;
    padding: 32px;
    display: flex;
    flex-direction: column;
    gap: 24px;
}

.table-controls {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 16px;
}

.search-wrapper {
    position: relative; /* Allowed for small icons */
    width: 320px;
}

.search-input {
    width: 100%;
    padding: 12px 45px 12px 20px;
    border: 1px solid var(--input-border);
    border-radius: 8px;
    font-size: 14px;
    font-family: inherit;
}

.search-wrapper i {
    position: absolute;
    right: 20px;
    top: 50%;
    transform: translateY(-50%);
    color: var(--text-main);
}

.sort-wrapper {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 14px;
    color: var(--text-muted);
}

.sort-select {
    padding: 12px 20px;
    border: 1px solid var(--input-border);
    border-radius: 8px;
    min-width: 114px;
    display: flex;
    justify-content: space-between;
    align-items: center;
    color: var(--text-main);
    cursor: pointer;
}

/* TABLE STYLES */
.bills-table {
    display: flex;
    flex-direction: column;
}

.bills-table__header {
    display: flex;
    padding: 12px 16px;
    border-bottom: 1px solid var(--border-color);
    font-size: 12px;
    color: var(--text-muted);
    font-weight: 400;
}

.col-title { flex: 1; }
.col-date { width: 150px; }
.col-amount { width: 100px; text-align: right; }

.bill-row {
    display: flex;
    align-items: center;
    padding: 20px 16px;
    border-bottom: 1px solid var(--border-color);
}

.bill-row:last-child {
    border-bottom: none;
}

.bill-row__info {
    display: flex;
    align-items: center;
    gap: 16px;
    flex: 1;
}

.bill-row__avatar {
    min-width: 32px;
    min-height: 32px;
    width: 32px;
    height: 32px;
    border-radius: 50%;
    object-fit: cover;
    background-color: var(--bg-color);
}

.bill-row__name {
    font-size: 14px;
    font-weight: 700;
    color: var(--text-main);
}

.bill-row__date-box {
    width: 150px;
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 12px;
    color: var(--primary-teal);
}

.bill-row__date-box--upcoming {
    color: var(--text-muted);
}

.bill-row__amount {
    width: 100px;
    text-align: right;
    font-size: 14px;
    font-weight: 700;
    color: var(--text-main);
}

.bill-row__amount--danger {
    color: var(--danger-red);
}

/* RESPONSIVE ADJUSTMENTS */
@media (max-width: 1100px) {
    .content-grid {
        flex-direction: column;
    }
    .content-left {
        width: 100%;
        flex-direction: row;
    }
    .total-bills-card, .summary-card {
        flex: 1;
    }
}

@media (max-width: 768px) {
    .sidebar {
        width: 80px;
    }
    .sidebar__logo-container, .sidebar__item span, .sidebar__logo {
        display: none;
    }
    .sidebar__item {
        padding: 16px;
        justify-content: center;
    }
    .content-left {
        flex-direction: column;
    }
}

:root {
    /* Colors from Original Data */
    --color-bg-app: rgb(248, 244, 240);
    --color-bg-main: rgb(242, 243, 247);
    --color-sidebar: rgb(32, 31, 36);
    --color-white: rgb(255, 255, 255);
    --color-teal: rgb(39, 124, 120);
    --color-green-accent: rgb(42, 207, 130);
    --color-danger: rgb(201, 71, 54);
    --color-text-dark: rgb(32, 31, 36);
    --color-text-muted: rgb(105, 104, 104);
    --color-text-sidebar: rgb(179, 179, 179);
    --color-border: rgb(219, 229, 230);
    --color-border-light: rgb(242, 242, 242);
    --color-input-border: rgb(152, 144, 139);

    /* Spacing & Sizing */
    --sidebar-width: 300px;
    --container-max-width: 1440px;
    --border-radius-lg: 12px;
    --border-radius-md: 8px;
    --transition-speed: 0.3s;
}

/* Base Reset */
* {
    box-sizing: border-box;
    word-break: break-word;
}

body {
    margin: 0;
    padding: 0;
    background-color: var(--color-bg-app);
}

/* Layout Container */
.app-container {
    display: flex;
    max-width: var(--container-max-width);
    margin: 0 auto;
    min-height: 1024px;
    font-family: 'Inter', sans-serif;
    background-color: var(--color-bg-app);
}

/* Sidebar Navigation */
.sidebar {
    width: var(--sidebar-width);
    background-color: var(--color-sidebar);
    display: flex;
    flex-direction: column;
    border-right: 1px solid var(--color-border);
    height: 1024px;
    flex-shrink: 0;
}

.sidebar__logo-container {
    height: 102px;
    background-color: var(--color-white);
    display: flex;
    align-items: center;
    padding-left: 32px;
    min-height: 102px;
}

.sidebar__logo {
    min-width: 121px;
    min-height: 22px;
    object-fit: contain;
}

.sidebar__menu {
    flex-grow: 1;
    display: flex;
    flex-direction: column;
    gap: 4px;
    padding-right: 24px;
    margin-top: 24px;
}

.sidebar__menu-item {
    display: flex;
    align-items: center;
    gap: 16px;
    padding: 16px 32px;
    text-decoration: none;
    transition: all var(--transition-speed) ease;
}

.sidebar__menu-item i {
    width: 24px;
    text-align: center;
    color: var(--color-text-sidebar);
}

.sidebar__menu-item span {
    color: var(--color-text-sidebar);
    font-weight: 700;
    font-size: 16px;
}

.sidebar__menu-item--active {
    background-color: var(--color-bg-app);
    border-left: 4px solid var(--color-teal);
    border-radius: 0 var(--border-radius-lg) var(--border-radius-lg) 0;
}

.sidebar__menu-item--active i {
    color: var(--color-teal);
}

.sidebar__menu-item--active span {
    color: var(--color-text-dark);
}

.sidebar__minimize {
    display: flex;
    align-items: center;
    gap: 16px;
    padding: 16px 32px;
    cursor: pointer;
    margin-bottom: 24px;
}

/* Main Content Area */
.main-content {
    flex-grow: 1;
    background-color: var(--color-bg-main);
    padding: 32px 40px;
    display: flex;
    flex-direction: column;
    gap: 32px;
}

.main-content__header h1 {
    font-size: 32px;
    font-weight: 700;
    color: var(--color-text-dark);
    margin: 0;
}

/* Bills Layout Grid */
.bills-layout {
    display: flex;
    gap: 24px;
    align-items: flex-start;
}

/* Left Side: Overview */
.bills-overview {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: 24px;
    max-width: 337px;
}

.card-total {
    background-color: var(--color-sidebar);
    padding: 24px;
    border-radius: var(--border-radius-lg);
    color: var(--color-white);
    display: flex;
    flex-direction: column;
    gap: 32px;
}

.card-total i {
    font-size: 40px;
}

.card-total__content p {
    font-size: 14px;
    margin: 0 0 11px 0;
    opacity: 0.9;
}

.card-total__content h2 {
    font-size: 32px;
    font-weight: 700;
    margin: 0;
}

.card-summary {
    background-color: var(--color-white);
    padding: 20px;
    border-radius: var(--border-radius-lg);
    display: flex;
    flex-direction: column;
    gap: 20px;
}

.card-summary h3 {
    font-size: 16px;
    font-weight: 700;
    color: var(--color-text-dark);
    margin: 0;
}

.card-summary__list {
    display: flex;
    flex-direction: column;
    gap: 16px;
}

.card-summary__item {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.card-summary__item span:first-child {
    font-size: 12px;
    color: var(--color-text-grey);
}

.card-summary__item span:last-child {
    font-size: 12px;
    font-weight: 700;
    color: var(--color-text-dark);
}

/* Right Side: Bills List */
.bills-list {
    flex: 2;
    background-color: var(--color-white);
    padding: 32px;
    border-radius: var(--border-radius-lg);
    display: flex;
    flex-direction: column;
    gap: 24px;
}

.bills-list__controls {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 16px;
}

.search-box {
    position: relative;
    width: 320px;
}

.search-box input {
    width: 100%;
    padding: 12px 20px;
    border: 1px solid var(--color-input-border);
    border-radius: var(--border-radius-md);
    font-size: 14px;
    outline: none;
}

.search-box i {
    position: absolute;
    right: 20px;
    top: 50%;
    transform: translateY(-50%);
    color: var(--color-text-dark);
}

.sort-box {
    display: flex;
    align-items: center;
    gap: 8px;
}

.sort-box > span {
    font-size: 14px;
    color: var(--color-text-grey);
}

.sort-box div {
    border: 1px solid var(--color-input-border);
    padding: 12px 20px;
    border-radius: var(--border-radius-md);
    display: flex;
    align-items: center;
    gap: 16px;
    cursor: pointer;
}

/* Table Styling */
.bills-table__header {
    display: flex;
    padding: 12px 16px;
    background-color: var(--color-green-accent);
    border: 1px solid var(--color-border-light);
    border-radius: 4px;
}

.bills-table__header span {
    font-size: 12px;
    color: var(--color-text-grey);
    font-weight: 400;
}

.bills-table__body {
    display: flex;
    flex-direction: column;
    gap: 20px;
}

.bills-table__row {
    display: flex;
    align-items: center;
    padding: 0 16px;
    min-height: 32px;
}

.bills-table__row img {
    min-width: 32px;
    min-height: 32px;
    border-radius: 50%;
    background-color: var(--color-bg-app);
}

.bills-table__row .bill-title-cell {
    flex: 1;
    display: flex;
    align-items: center;
    gap: 16px;
}

.bills-table__row .due-date-cell {
    width: 120px;
    display: flex;
    align-items: center;
    gap: 8px;
}

.bills-table__row .amount-cell {
    width: 100px;
    text-align: right;
    font-weight: 700;
}

/* Utility Classes for Table Content */
.text-teal { color: var(--color-teal) !important; }
.text-danger { color: var(--color-danger) !important; }
.text-bold { font-weight: 700; }
.text-small { font-size: 12px; }
.text-base { font-size: 14px; }

hr {
    border: 0;
    border-top: 1px solid var(--color-border-light);
    margin: 0;
}

/* Responsive Adjustments */
@media (max-width: 1024px) {
    .bills-layout {
        flex-direction: column;
    }
    .bills-overview {
        max-width: 100%;
        width: 100%;
    }
    .bills-list {
        width: 100%;
    }
}

